V &= \int_0^{2\pi} \int_0^{\arctan(a/h)} \left[ \frac{\rho^3}{3} \right]_0^{h/\cos \phi} \sin \phi \, d\phi \, d\theta \\
&= \frac{1}{3} \int_0^{2\pi} \int_0^{\arctan(a/h)} \frac{h^3}{\cos^3 \phi} \sin \phi \, d\phi \, d\theta \\
&= \frac{h^3}{3} \int_0^{2\pi} \int_0^{\arctan(a/h)} \frac{\sin \phi}{\cos^3 \phi} \, d\phi \, d\theta \\
&= \frac{h^3}{3} \int_0^{2\pi} \left[ -\frac{1}{2\cos^2 \phi} \right]_0^{\arctan(a/h)} \, d\theta \\
&= \frac{h^3}{6} \int_0^{2\pi} \left( 1 - \frac{1}{\cos^2(\arctan(a/h))} \right) \, d\theta \\
&= \frac{h^3}{6} \int_0^{2\pi} \left( 1 - \frac{1 + (a/h)^2}{(a/h)^2} \right) \, d\theta \\
&= \frac{h^3}{6} \int_0^{2\pi} \left( 1 - \frac{h^2 + a^2}{a^2} \right) \, d\theta \\
&= \frac{h^3}{6} \cdot 2\pi \cdot \frac{a^2 - h^2}{a^2} \\
&= \frac{\pi a^2 h}{3}
\end{align*}

\subsection*{Result}
$$\boxed{V = \frac{1}{3}\pi a^2 h}$$

