        self.money = 10000
        self.inventory = {}
        self.prices = {}
        self.supply_demand = {}
        self.week = 1
        self.game_running = True

    def initialize_market(self):
        products = ["widgets", "gadgets", "tools", "materials"]
        for product in products:
            self.prices[product] = random.randint(50, 200)
            self.supply_demand[product] = {"supply": 100, "demand": 100}

    def update_market(self):
        for product in self.prices:
            # Random market fluctuations
            change = random.uniform(-0.1, 0.1)
            self.prices[product] *= (1 + change)

            # Supply/demand dynamics
            self.supply_demand[product]["supply"] += random.randint(-10, 10)
            self.supply_demand[product]["demand"] += random.randint(-10, 10)

            # Ensure values don't go negative
            self.supply_demand[product]["supply"] = max(0, self.supply_demand[product]["supply"])
            self.supply_demand[product]["demand"] = max(0, self.supply_demand[product]["demand"])

    def buy_product(self, product: str, quantity: int):
        if product not in self.prices:
            print("Product not available")
            return

        cost = self.prices[product] * quantity
        if self.money < cost:
            print("Not enough money")
            return

        self.money -= cost
        self.inventory[product] = self.inventory.get(product, 0) + quantity
        print(f"Bought {quantity} {product}(s) for ${cost}")

    def sell_product(self, product: str, quantity: int):
        if product not in self.inventory or self.inventory[product] < quantity:
            print("Not enough inventory")
            return

        revenue = self.prices[product] * quantity
        self.money += revenue
        self.inventory[product] -= quantity
        if self.inventory[product] == 0:
            del self.inventory[product]
        print(f"Sold {quantity} {product}(s) for ${revenue}")

def main():
    game = BusinessGame()
    game.initialize_market()

    print("Welcome to Business Simulator!")
    print("Commands: buy [product] [qty], sell [product] [qty], status, quit")

    while game.game_running:
        try:
            command = input(f"\nWeek {game.week} - Money: ${game.money}\n> ").strip().lower()

            if command == "quit":
                game.game_running = False
                break
            elif command == "status":
                print(f"Inventory: {game.inventory}")
                print(f"Prices: {game.prices}")
            elif command.startswith("buy"):
