import sys

def parse_dfs_string(s):
    """Parse DFS string and return tree structure"""
    stack = []
    tree = {}

    for i, char in enumerate(s):
        if char == 'd':
            if not stack:
                tree[i] = []
            else:
                parent = stack[-1]
                if parent not in tree:
                    tree[parent] = []
                tree[parent].append(i)
            stack.append(i)
        elif char == 'u':
            if stack:
                stack.pop()

    return tree

def compute_tree_height(tree, node=0):
    """Compute height of ordered tree"""
    if node not in tree or not tree[node]:
        return 0

    max_height = 0
    for child in tree[node]:
        max_height = max(max_height, compute_tree_height(tree, child))

    return max_height + 1

def convert_to_lcrs(tree):
    """Convert ordered tree to left-child right-sibling representation"""
    lcrs_tree = {}

    def build_lcrs(node, parent=None):
        if node not in tree:
            return None

        children = tree[node]
        if not children:
            return None

        # First child becomes left child
        left_child = children[0]
        lcrs_tree[node] = [left_child, None]  # [left, right]

        # Set siblings as right children
        current_sibling = left_child
        for i in range(1, len(children)):
            sibling = children[i]
            lcrs_tree[current_sibling][1] = sibling  # Set right child
            current_sibling = sibling
            lcrs_tree[current_sibling] = [None, None]  # Initialize

        # Recursively process children
        for child in children:
            build_lcrs(child, node)

        return left_child

    # Build LCRS structure
    root_nodes = [k for k in tree.keys() if k not in [item for sublist in tree.values() for item in sublist]]

    for root in root_nodes:
        build_lcrs(root)

    return lcrs_tree

def compute_lcrs_height(lcrs_tree):
    """Compute height of LCRS tree"""
    if not lcrs_tree:
        return 0

    # Find root (node with no parent)
    all_children = set()
    for children in lcrs_tree.values():
        if children[0]: all_children.add(children[0])
        if children[1]: all_children.add(children[1])

    roots = set(lcrs_tree.keys()) - all_children
    if not roots:
        return 0

    root = list(roots)[0]

    def get_height(node):
        if node not in lcrs_tree:
            return 0

        left_child = lcrs_tree[node][0]
        right_child = lcrs_tree[node][1]

        # Height is max of left subtree + 1
        left_height = get_height(left_child) if left_child else 0
        right_height = get_height(right_child) if right_child else 0

        return max(left_height, right_height) + 1

    return get_height(root)

