    """Find similar images using perceptual hashes"""
    hash_dict = defaultdict(list)

    # Supported image extensions
    extensions = {'.jpg', '.jpeg', '.png', '.bmp', '.tiff', '.webp'}

    # Walk through directory
    for root, _, files in os.walk(directory):
        for file in files:
            if os.path.splitext(file)[1].lower() in extensions:
                filepath = os.path.join(root, file)
                phash = calculate_phash(filepath)
                if phash is not None:
                    hash_dict[phash].append(filepath)

    # Group similar images
    similar_groups = []
    processed = set()

    for phash, files in hash_dict.items():
        if phash in processed:
            continue

        group = [f for f in files if calculate_phash(f) == phash]
