    pub fn new(oram_size: usize, bucket_size: usize, key: &[u8; 32]) -> Result<Self, ORAMError> {
        let cipher = Aes256Gcm::new(Key::from_slice(key));
        let mut buckets = Vec::with_capacity(oram_size);

        for _ in 0..oram_size {
