        Ok(Some(block.value))
    }

    pub fn write(&mut self, key: Vec<u8>, value: Vec<u8>) -> Result<(), ORAMError> {
        let block = Block::new(key.clone(), value);
        let encrypted_block = self.encrypt_block(&block)?;

        // Oblivious placement
        let mut accessed_buckets = Vec::new();
        for _ in 0..self.oram_size {
            accessed_buckets.push(self.get_random_bucket());
        }

        // Access all buckets in random order
        for &idx in &accessed_buckets {
            if idx < self.buckets.len() && !self.buckets[idx].is_empty() {
                let pos = self.get_random_position_in_bucket(idx);
                if pos < self.buckets[idx].len() {
                    let _ = self.buckets[idx][pos].clone();
                }
            }
        }

        // Place the new block
        let bucket_idx = self.get_random_bucket();
        let block_idx = self.get_random_position_in_bucket(bucket_idx);

        if self.buckets[bucket_idx].len() >= self.bucket_size {
