    public static int[][] computeLAT(int[] sbox) {
        int n = sbox.length;
        int[][] lat = new int[n][n];

        for (int a = 0; a < n; a++) {
            for (int b = 0; b < n; b++) {
                int count = 0;
                for (int x = 0; x < n; x++) {
