class MonotonicAssignment:
    def __init__(self):
        self.lattice_elements = {}

    def join(self, a, b):
        """Join operation for lattice elements"""
        if a.value >= b.value:
            return a
        return b

    def assign(self, var, value):
        """Assign value to variable maintaining monotonicity"""
        new_element = LatticeElement(value)

        if var not in self.lattice_elements:
            self.lattice_elements[var] = new_element
        else:
            # Ensure monotonicity - only allow increasing values
            current = self.lattice_elements[var]
            if value >= current.value:
                self.lattice_elements[var] = self.join(current, new_element)
            else:
                raise ValueError(f"Non-monotonic assignment: {value} < {current.value}")

