function* handleOutstandingTransactions(
  transactions: Transaction[]
): Generator<any, any, any> {
  try {
    // Separate charges and payments
    const charges: Charge[] = transactions
      .filter(t => t.type === 'charge')
      .map(t => ({ id: t.id, amount: t.amount }));

    const payments: Payment[] = transactions
      .filter(t => t.type === 'payment')
      .map(t => ({ id: t.id, amount: t.amount }));

    // Calculate totals
    const totalCharges = charges.reduce((sum, charge) => sum + charge.amount, 0);
    const totalPayments = payments.reduce((sum, payment) => sum + payment.amount, 0);

    // Process adjustments
    let remainingBalance = totalCharges - totalPayments;
    let adjustedPayments = [...payments];
    let adjustedCharges = [...charges];

    // Apply payments to charges
    for (const payment of payments) {
      if (remainingBalance <= 0) break;

      const chargeIndex = adjustedCharges.findIndex(c => c.amount > 0);
      if (chargeIndex === -1) break;

      const charge = adjustedCharges[chargeIndex];
      const adjustmentAmount = Math.min(payment.amount, charge.amount);

      // Update amounts
      charge.amount -= adjustmentAmount;
      remainingBalance -= adjustmentAmount;

      // Remove zero-amount charges
      if (charge.amount === 0) {
        adjustedCharges.splice(chargeIndex, 1);
      }
    }

    return {
      charges: adjustedCharges,
      payments: adjustedPayments,
      remainingBalance
    };
  } catch (error) {
    console.error('Error processing outstanding transactions:', error);
    throw new Error('Failed to process outstanding transactions');
  }
}
