        id: doc.id,
        ...doc.data()
      } as Document));
      setDocs(documents);
    } catch (error) {
      console.error('Error fetching documents:', error);
    }
  };

  const handleCreate = async (title: string, content: string) => {
    try {
      await addDoc(collection(db, 'documents'), { title, content, createdAt: new Date() });
      fetchDocs();
      setIsEditing(false);
    } catch (error) {
      console.error('Error creating document:', error);
    }
  };

  const handleUpdate = async (id: string, title: string, content: string) => {
    try {
      await updateDoc(doc(db, 'documents', id), { title, content });
      fetchDocs();
      setIsEditing(false);
    } catch (error) {
      console.error('Error updating document:', error);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await deleteDoc(doc(db, 'documents', id));
      fetchDocs();
      if (selectedDoc?.id === id) setSelectedDoc(null);
    } catch (error) {
      console.error('Error deleting document:', error);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="container mx-auto px-4 py-8">
        <header className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900">Documentation</h1>
          <p className="text-gray-600">Manage your project documentation</p>
        </header>

        <div className="flex flex-col lg:flex-row gap-6">
          {/* Document List */}
          <div className="w-full lg:w-1/3">
            <div className="bg-white rounded-lg shadow p-4 mb-4">
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-xl font-semibold">Documents</h2>
                <button 
                  onClick={() => {
                    setSelectedDoc(null);
                    setIsEditing(true);
                  }}
                  className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-md text-sm"
                >
                  New Doc
                </button>
              </div>

              <div className="space-y-2 max-h-[calc(100vh-200px)] overflow-y-auto">
                {docs.map(doc => (
                  <div 
                    key={doc.id}
                    onClick={() => {
                      setSelectedDoc(doc);
                      setIsEditing(false);
                    }}
                    className={`p-3 rounded-md cursor-pointer transition-colors ${
                      selectedDoc?.id === doc.id 
                        ? 'bg-blue-100 border-l-4 border-blue-500' 
                        : 'hover:bg-gray-100'
                    }`}
                  >
                    <h3 className="font-medium text-gray-900 truncate">{doc.title}</h3>
                    <p className="text-xs text-gray-500 mt-1">
                      {new Date(doc.createdAt?.toDate()).toLocaleDateString()}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Editor/Viewer */}
          <div className="w-full lg:w-2/3">
            {isEditing ? (
              <Editor 
                initialDoc={selectedDoc} 
                onSave={selectedDoc ? handleUpdate : handleCreate}
                onCancel={() => setIsEditing(false)}
              />
            ) : selectedDoc ? (
              <Viewer 
                doc={selectedDoc} 
                onEdit={() => setIsEditing(true)}
                onDelete={handleDelete}
              />
            ) : (
              <div className="bg-white rounded-lg shadow p-8 text-center">
                <h3 className="text-lg font-medium text-gray-900 mb-2">No Document Selected</h3>
                <p className="text-gray-500">Select a document or create a new one to get started</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
