            if token_type not in ['WHITESPACE']:
                tokens.append((token_type, value))
        return tokens

class LL1Parser:
    def __init__(self):
        # Grammar rules
        self.rules = {
            'E': [['T', 'E\'']],
            'E\'': [['PLUS', 'T', 'E\''], ['MINUS', 'T', 'E\''], ['EPSILON']],
            'T': [['F', 'T\'']],
            'T\'': [['MULTIPLY', 'F', 'T\''], ['DIVIDE', 'F', 'T\''], ['EPSILON']],
            'F': [['IDENTIFIER'], ['NUMBER'], ['LPAREN', 'E', 'RPAREN']],
            'S': [['E', 'SEMICOLON'], ['WHILE', 'LPAREN', 'E', 'RPAREN', 'S'], 
                  ['FOR', 'LPAREN', 'E', 'SEMICOLON', 'E', 'SEMICOLON', 'E', 'RPAREN', 'S'],
                  ['IF', 'LPAREN', 'E', 'RPAREN', 'S', 'ELSE', 'S'], ['BREAK', 'SEMICOLON'],
                  ['CONTINUE', 'SEMICOLON'], ['RETURN', 'E', 'SEMICOLON'], ['CALL']],
            'CALL': [['IDENTIFIER', 'LPAREN', 'ARGS', 'RPAREN']],
            'ARGS': [['E', 'COMMA', 'ARGS'], ['E'], ['EPSILON']]
        }

        self.non_terminals = set(self.rules.keys())
        self.terminals = {'PLUS', 'MINUS', 'MULTIPLY', 'DIVIDE', 'LPAREN', 'RPAREN', 
                         'IDENTIFIER', 'NUMBER', 'SEMICOLON', 'WHILE', 'FOR', 'IF', 
                         'ELSE', 'BREAK', 'CONTINUE', 'RETURN', 'COMMA', 'LT', 'GT', 
                         'LE', 'GE', 'EQ', 'NE'}
        self.terminals.add('EOF')

        self.first = {}
        self.follow = {}
        self.parsing_table = {}

    def compute_first(self):
        # Initialize FIRST sets
        for nt in self.non_terminals:
            self.first[nt] = set()

        # Add terminals to FIRST sets
        for terminal in self.terminals:
            self.first[terminal] = {terminal}
        self.first['EPSILON'] = {'EPSILON'}

        # Compute FIRST sets iteratively
        changed = True
        while changed:
            changed = False
            for lhs, rhs_list in self.rules.items():
                for rhs in rhs_list:
                    first_set = self._first_of_sequence(rhs)
                    old_size = len(self.first[lhs])
                    self.first[lhs].update(first_set)
                    if len(self.first[lhs]) != old_size:
                        changed = True

    def _first_of_sequence(self, sequence):
        result = set()
        for symbol in sequence:
            if symbol in self.terminals or symbol == 'EPSILON':
                result.add(symbol)
                break
            else:
                result.update(self.first[symbol] - {'EPSILON'})
                if 'EPSILON' not in self.first[symbol]:
                    break
        else:
            result.add('EPSILON')
        return result

    def compute_follow(self):
        # Initialize FOLLOW sets
        for nt in self.non_terminals:
            self.follow[nt] = set()
        self.follow['S'].add('EOF')

        # Compute FOLLOW sets iteratively
        changed = True
        while changed:
            changed = False
            for lhs, rhs_list in self.rules.items():
                for rhs in rhs_list:
                    for i, symbol in enumerate(rhs):
                        if symbol in self.non_terminals:
                            # Get FOLLOW of symbol
                            follow_set = set()
                            if i < len(rhs) - 1:
                                # Look at symbols after current symbol
                                first_of_suffix = self._first_of_sequence(rhs[i+1:])
                                follow_set = first_of_suffix - {'EPSILON'}
                                if 'EPSILON' in first_of_suffix:
                                    follow_set.update(self.follow[lhs])
                            else:
                                # Symbol is last in production, add FOLLOW of LHS
                                follow_set = self.follow[lhs]

                            old_size = len(self.follow[symbol])
                            self.follow[symbol].update(follow_set)
                            if len(self.follow[symbol]) != old_size:
                                changed = True

    def build_parsing_table(self):
        for lhs, rhs_list in self.rules.items():
            for rhs in rhs_list:
                first_set = self._first_of_sequence(rhs)
                for symbol in first_set:
                    if symbol != 'EPSILON':
                        self.parsing_table[(lhs, symbol)] = rhs
                if 'EPSILON' in first_set:
                    for symbol in self.follow[lhs]:
                        self.parsing_table[(lhs, symbol)] = rhs

    def parse(self, tokens):
        stack = ['S', 'EOF']
        input_tokens = tokens + [('EOF', 'EOF')]
        position = 0

        print("Parsing steps:")
        print("Stack\t\tInput\t\tAction")
        print("-" * 50)

        while stack and position < len(input_tokens):
            top = stack.pop()
            current_token = input_tokens[position]

            if top == current_token[0]:
                position += 1
                print(f"{stack}\t\t{input_tokens[position:]}\t\tMatched {top}")
            elif top in self.non_terminals:
                if (top, current_token[0]) in self.parsing_table:
                    production = self.parsing_table[(top, current_token[0])]
                    print(f"{stack}\t\t{input_tokens[position:]}\t\tApply {top} -> {' '.join(production)}")
                    # Push production in reverse order
                    for symbol in reversed(production):
                        if symbol != 'EPSILON':
                            stack.append(symbol)
                else:
                    raise SyntaxError(f"Unexpected token {current_token[0]} at position {position}")
            else:
                raise SyntaxError(f"Unexpected symbol {top} at position {position}")

        if not stack and position == len(input_tokens):
            print("Parsing successful!")
        else:
            raise SyntaxError("Parsing failed")

def main():
    # Create parser
    parser = LL1Parser()

    # Compute FIRST and FOLLOW sets
    parser.compute_first()
    parser.compute_follow()
    parser.build_parsing_table()

    # Display FIRST sets
    print("FIRST Sets:")
    table = PrettyTable(['Non-terminal', 'FIRST'])
    for nt, first_set in parser.first.items():
        table.add_row([nt, ', '.join(sorted(first_set))])
    print(table)

    # Display FOLLOW sets
    print("\nFOLLOW Sets:")
    table = PrettyTable(['Non-terminal', 'FOLLOW'])
    for nt, follow_set in parser.follow.items():
        table.add_row([nt, ', '.join(sorted(follow_set))])
    print(table)

    # Display Parsing Table
    print("\nParsing Table:")
    table = PrettyTable(['Non-terminal'] + sorted(parser.terminals))
    for nt in sorted(parser.non_terminals):
        row = [nt]
        for terminal in sorted(parser.terminals):
            if (nt, terminal) in parser.parsing_table:
                row.append(' '.join(parser.parsing_table[(nt, terminal)]))
            else:
                row.append('')
        table.add_row(row)
    print(table)

    # Test parsing
    lexer = Lexer()
    test_code = "while (x > 0) { x = x - 1; }"
    try:
        tokens = lexer.tokenize(test_code)
        print(f"\nTokens: {tokens}")
        parser.parse(tokens)
    except Exception as e:
        print(f"Parsing error: {e}")

if __name__ == "__main__":
    main()
