// BountyCommand.java
import org.bukkit.command.Command;
import org.bukkit.command.CommandExecutor;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;
import java.util.Locale;

public class BountyCommand implements CommandExecutor {
    private final BountyPlugin plugin;

    public BountyCommand(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @Override
    public boolean onCommand(CommandSender sender, Command cmd, String label, String[] args) {
        if (args.length == 0) {
            sender.sendMessage("Usage: /bounty <player>");
            return true;
        }

        if (args[0].toLowerCase(Locale.ENGLISH).equals("add")) {
            if (!(sender instanceof Player)) {
                sender.sendMessage("Only players can use this command.");
                return true;
            }

            if (args.length != 3) {
                sender.sendMessage("Usage: /bounty add <player> <amount>");
                return true;
            }

            Player player = (Player) sender;
            String target = args[1];
            double amount;

            try {
                amount = Double.parseDouble(args[2]);
            } catch (NumberFormatException e) {
                sender.sendMessage("Invalid amount.");
                return true;
            }

            if (amount <= 0) {
                sender.sendMessage("Amount must be positive.");
                return true;
            }

            if (!plugin.getConfigManager().isWorldEnabled(player.getWorld().getName())) {
                sender.sendMessage("Bounties not allowed in this world.");
                return true;
            }

            if (!plugin.getEconomy().has(player.getName(), amount)) {
                sender.sendMessage("You don't have enough money.");
                return true;
            }

            plugin.getEconomy().withdraw(player.getName(), amount);
            plugin.getBounties().put(target.toLowerCase(), 
                plugin.getBounties().getOrDefault(target.toLowerCase(), 0.0) + amount);
            sender.sendMessage("Added $" + amount + " to " + target + "'s bounty.");
            return true;
        }

        // Show bounty
        String target = args[0];
        double bounty = plugin.getBounties().getOrDefault(target.toLowerCase(), 0.0);
        sender.sendMessage(target + " has a bounty of $" + bounty);
        return true;
    }
}
