import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.entity.PlayerDeathEvent;
import org.bukkit.entity.Player;
import org.bukkit.entity.Entity;

public class BountyListener implements Listener {
    private final BountyPlugin plugin;

    public BountyListener(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @EventHandler
    public void onPlayerDeath(PlayerDeathEvent event) {
        Player victim = event.getEntity();
        Entity killer = victim.getKiller();

        if (killer instanceof Player) {
            Player player = (Player) killer;
            String victimName = victim.getName().toLowerCase();

            if (!plugin.getConfigManager().isWorldEnabled(victim.getWorld().getName())) {
                return;
            }

            double bounty = plugin.getBounties().remove(victimName);
            if (bounty > 0) {
                plugin.getEconomy().deposit(player.getName(), bounty);
                player.sendMessage("You received $" + bounty + " for killing " + victimName);
                victim.sendMessage("You were killed by " + player.getName() + ". Your bounty of $" + bounty + " was paid out.");
            }
        }
    }
}
