import org.bukkit.plugin.RegisteredServiceProvider;
import net.milkbowl.vault.economy.Economy;

public class EconomyHandler {
    private Economy economy;

    public EconomyHandler(BountyPlugin plugin) {
        if (!setupEconomy(plugin)) {
            plugin.getLogger().severe("Vault not found! Economy features disabled.");
        }
    }

    private boolean setupEconomy(BountyPlugin plugin) {
        if (plugin.getServer().getPluginManager().getPlugin("Vault") == null) {
            return false;
        }

        RegisteredServiceProvider<Economy> rsp = plugin.getServer().getServicesManager()
            .getRegistration(Economy.class);
        if (rsp == null) {
            return false;
        }

        economy = rsp.getProvider();
        return economy != null;
    }

    public boolean has(String player, double amount) {
        return economy.has(player, amount);
    }

    public void withdraw(String player, double amount) {
        economy.withdrawPlayer(player, amount);
    }

    public void deposit(String player, double amount) {
        economy.depositPlayer(player, amount);
    }
}
