def count_ways(amount, coin_index, memo={}):
    if amount == 0:
        return 1
    if amount < 0 or coin_index < 0:
        return 0

    if (amount, coin_index) in memo:
        return memo[(amount, coin_index)]

    # Take current coin or skip it
