void FileManagement::saveRatings(const std::map<std::string, PlayerRating>& ratings) {
    std::ofstream file("ratings.txt");
    if (file.is_open()) {
        for (const auto& pair : ratings) {
            const auto& name = pair.first;
            const auto& rating = pair.second;
            file << name << " " << rating.wins << " " << rating.losses << " " << rating.gamesPlayed << "\n";
        }
        file.close();
    }
}

std::map<std::string, PlayerRating> FileManagement::loadRatings() {
    std::map<std::string, PlayerRating> ratings;
    std::ifstream file("ratings.txt");
    if (file.is_open()) {
        std::string line;
        while (std::getline(file, line)) {
            std::istringstream iss(line);
            std::string name;
            int wins, losses, games;
            if (iss >> name >> wins >> losses >> games) {
                ratings[name] = {wins, losses, games};
            }
        }
        file.close();
    }
    return ratings;
}

void FileManagement::updateRating(const std::string& playerName, bool win) {
    auto ratings = loadRatings();
    auto& rating = ratings[playerName];
    rating.gamesPlayed++;
    if (win) rating.wins++;
    else rating.losses++;
    saveRatings(ratings);
